{
  "mode": "All",
  "parameters": {
    "lockName": {
      "type": "String",
      "defaultValue": "auto-readonly"
    }
  },
  "policyRule": {
    "if": {
      "allOf": [
        {
          "field": "type",
          "equals": "Microsoft.Resources/resourceGroups"
        },
        {
          "field": "tags['Environment']",
          "equals": "prod"
        }
      ]
    },
    "then": {
      "effect": "DeployIfNotExists",
      "details": {
        "type": "Microsoft.Authorization/locks",
        "existenceCondition": {
          "field": "Microsoft.Authorization/locks/level",
          "equals": "ReadOnly"
        },
        "roleDefinitionIds": [
          "/providers/microsoft.authorization/roleDefinitions/8e3af657-a8ff-443c-a75c-2fe8c4bcb635"
        ],
        "deployment": {
          "properties": {
            "mode": "incremental",
            "template": {
              "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
              "contentVersion": "1.0.0.0",
              "parameters": {
                "lockName": { "type": "string" }
              },
              "resources": [
                {
                  "type": "Microsoft.Authorization/locks",
                  "apiVersion": "2017-04-01",
                  "name": "[parameters('lockName')]",
                  "properties": {
                    "level": "ReadOnly",
                    "notes": "Auto-applied by Azure Policy to all prod resource groups"
                  }
                }
              ]
            },
            "parameters": {
              "lockName": { "value": "[parameters('lockName')]" }
            }
          }
        }
      }
    }
  }
}

# Apply ReadOnly lock to all production resource groups across a management group
# Run in Azure Cloud Shell or Azure Automation

$mgId = 'mg-corp'
$lockName = 'prod-readonly'

# Get all subscriptions in the management group
$subs = Get-AzManagementGroupSubscription -GroupId $mgId

foreach ($sub in $subs) {
    Set-AzContext -SubscriptionId $sub.Id | Out-Null

    # Get all resource groups tagged Environment=prod
    $prodRGs = Get-AzResourceGroup | Where-Object {
        $_.Tags -and $_.Tags['Environment'] -eq 'prod'
    }

    foreach ($rg in $prodRGs) {
        # Check if lock already exists
        $existing = Get-AzResourceLock -ResourceGroupName $rg.ResourceGroupName -ErrorAction SilentlyContinue |
            Where-Object { $_.Name -eq $lockName }

        if (-not $existing) {
            New-AzResourceLock `
                -LockName $lockName `
                -LockLevel ReadOnly `
                -ResourceGroupName $rg.ResourceGroupName `
                -Force
            Write-Host "Lock applied: $($rg.ResourceGroupName)"
        } else {
            Write-Host "Already locked: $($rg.ResourceGroupName)"
        }
    }
}

# Generate lock inventory report
$report = foreach ($sub in $subs) {
    Set-AzContext -SubscriptionId $sub.Id | Out-Null
    Get-AzResourceLock | Select-Object `
        @{N='Subscription';E={$sub.Id}},
        Name,
        @{N='LockLevel';E={$_.Properties.Level}},
        @{N='Scope';E={$_.ResourceId}},
        @{N='Notes';E={$_.Properties.Notes}}
}
$report | Export-Csv -Path "lock-inventory-$(Get-Date -Format yyyyMMdd).csv" -NoTypeInformation
Write-Host "Report saved: lock-inventory-$(Get-Date -Format yyyyMMdd).csv"
